import React, { useMemo } from 'react';

const TokenViewer = ({ data }) => {
  const getTokenTypeInfo = (type) => {
    const typeInfo = {
      'NAME': { color: '#2563eb', description: 'Identifiers (variables, functions, classes)', icon: '🏷️' },
      'NUMBER': { color: '#059669', description: 'Numeric literals (integers, floats)', icon: '🔢' },
      'STRING': { color: '#dc2626', description: 'String literals (text enclosed in quotes)', icon: '📝' },
      'OP': { color: '#7c3aed', description: 'Operators (+, -, *, /, ==, !=, etc.)', icon: '⚡' },
      'DELIM': { color: '#ea580c', description: 'Delimiters (, ; : . ( ) [ ] { })', icon: '🔗' },
      'COMMENT': { color: '#6b7280', description: 'Comments in code', icon: '💬' },
      'NL': { color: '#9ca3af', description: 'New line character', icon: '↵' },
      'NEWLINE': { color: '#9ca3af', description: 'New line statement', icon: '📍' },
      'INDENT': { color: '#f59e0b', description: 'Code indentation increase', icon: '→' },
      'DEDENT': { color: '#f59e0b', description: 'Code indentation decrease', icon: '←' },
      'ENDMARKER': { color: '#ef4444', description: 'End of file marker', icon: '🏁' }
    };
    return typeInfo[type] || { color: '#374151', description: 'Unknown token type', icon: '❓' };
  };

  if (!data || data.length === 0) {
    return (
      <div className="viewer-empty">
        <p>No tokens to display. Please analyze some Python code first.</p>
      </div>
    );
  }

  if (data.length === 1 && data[0].error) {
    return (
      <div className="error-message">
        <strong>Tokenization Error:</strong> {data[0].error}
      </div>
    );
  }

  return (
    <div className="token-viewer-container">
      <div className="token-viewer-card">
        <div className="card-header">
          <h3 className="card-title">🔍 Lexical Analysis</h3>
        </div>

        <div className="table-section">
          <div className="table-container">
            <table className="token-table">
              <thead>
                <tr>
                  <th className="table-header">Line</th>
                  <th className="table-header">Column</th>
                  <th className="table-header">Type</th>
                  <th className="table-header">Value</th>
                  <th className="table-header">Position</th>
                </tr>
              </thead>
              <tbody>
                {data.map((token, index) => (
                  <tr key={index} className={index % 2 === 0 ? 'even-row' : 'odd-row'}>
                    <td className="table-cell">{token.line}</td>
                    <td className="table-cell">{token.column}</td>
                    <td className="table-cell">
                      <span className="token-type-badge" style={{ backgroundColor: getTokenTypeColor(token.type) }}>
                        {token.type}
                      </span>
                    </td>
                    <td className="table-cell">
                      <code className="token-value">{token.value || '·'}</code>
                    </td>
                    <td className="table-cell">
                      {token.end_line}:{token.end_column}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );

  function getTokenTypeColor(type) {
    const colors = {
      'NAME': '#dc2626',
      'NUMBER': '#059669',
      'STRING': '#7c3aed',
      'OP': '#ea580c',
      'DELIM': '#6b7280',
      'COMMENT': '#9ca3af',
      'NL': '#9ca3af',
      'NEWLINE': '#9ca3af',
      'INDENT': '#f59e0b',
      'DEDENT': '#f59e0b',
      'ENDMARKER': '#ef4444'
    };
    return colors[type] || '#374151';
  }
};

export default TokenViewer;
